import type { Method, NamedType, OpensdkSpecJson, Resource } from '@xyd-js/opensdk-core';

/**
 * How writeProject treats a generated file that already exists on disk:
 * - 'overwrite'    — replace it (identical bytes are a no-op, so mtimes stay stable);
 * - 'skipIfExists' — user-owned scaffold (README, go.mod): never clobber an existing file;
 * - 'mergeJson'    — deep-merge the generated JSON INTO the existing file's JSON
 *                    (existing user keys win; arrays replace as a unit, never element-merge).
 */
export type WriteMode = 'overwrite' | 'skipIfExists' | 'mergeJson';

/** One generated file, path relative to the project root. */
export interface GeneratedFile {
  path: string;
  content: string;
  /** Per-file write semantics for writeProject. Default: 'overwrite'. */
  writeMode?: WriteMode;
}

/** A project file-map entry that preserves per-file write semantics across the orchestrator. */
export interface GeneratedFileEntry {
  content: string;
  writeMode?: WriteMode;
}

/**
 * The virtual project file map writeProject consumes. A plain string value means
 * 'overwrite' — the historical `Record<path, contents>` shape stays valid.
 */
export type ProjectFileMap = Record<string, string | GeneratedFileEntry>;

/** Context threaded through every emitter capability method. */
export interface EmitterContext {
  /** The full OpenSDK IR document. */
  spec: OpensdkSpecJson;
  /** Symbol table: every named type in the IR, by name. */
  types: Map<string, NamedType>;
  /** Language-specific options for the active emitter (e.g. modulePath, packageName). */
  emitterOptions: Record<string, unknown>;
}

/**
 * The emitter plugin contract (modeled on oagen's Emitter). Every language
 * target implements this; the framework orchestrator drives it.
 *
 * Rules:
 * - Capability methods are PURE: IR in, GeneratedFile[] out. No I/O.
 * - Empty input => empty output (no errors).
 * - Two methods may not emit the same path (the orchestrator throws).
 * - `fileHeader` (optional) is the machine-ownership marker: the orchestrator
 *   prepends it to every generated file using the file extension's comment
 *   syntax, exactly once. It is what the regen lifecycle (manifest + guarded
 *   stale-prune in writeProject) keys "generated, safe to manage" off.
 * - `GeneratedFile.writeMode` (optional, default 'overwrite') declares per-file
 *   regen semantics: mark user-owned scaffold 'skipIfExists' (README, go.mod)
 *   and mergeable manifests 'mergeJson' (package.json) so `generate` is safely
 *   re-runnable into a live directory.
 */
export interface Emitter {
  /** Language id, e.g. "go" | "python". Registry key. */
  language: string;

  /**
   * Optional ownership header text, e.g. 'Code generated by opensdk. DO NOT EDIT.'.
   * The orchestrator renders it with the per-extension comment syntax and
   * prepends it (header + blank line) to every generated file it knows the
   * comment syntax for; unknown extensions (.json, .md, .mod, .sum, none) are
   * left untouched. Idempotent: a file that already starts with the rendered
   * header is not double-prefixed. Return null to opt out for a given run.
   */
  fileHeader?(ctx: EmitterContext): string | null;

  /** Named types (structs/enums/unions/aliases), e.g. types.go / models.py. */
  generateTypes(types: NamedType[], ctx: EmitterContext): GeneratedFile[];

  /** Resource services with their typed methods, e.g. one <resource>.go per top-level resource. */
  generateResources(resources: Resource[], ctx: EmitterContext): GeneratedFile[];

  /** The top-level client, e.g. client.go / _client.py. */
  generateClient(spec: OpensdkSpecJson, ctx: EmitterContext): GeneratedFile[];

  /** The vendored runtime (transport/auth/serialization), e.g. option/ + internal/requestconfig/. */
  generateRuntime(spec: OpensdkSpecJson, ctx: EmitterContext): GeneratedFile[];

  /** Project manifest files, e.g. go.mod / pyproject.toml. */
  generateProject(spec: OpensdkSpecJson, ctx: EmitterContext): GeneratedFile[];

  /**
   * The SDK's OWN test suite (optional) — the artifact openai-go/openai-python
   * ship: one `<resource>_test.go` / `tests/test_<resource>.py` per resource
   * that constructs a client against a mock base URL, calls every method with
   * example values (a required-only case plus a "with all params" case when the
   * method has optionals), guards empty path params, and checks the typed error.
   * Example values come from the shared example planner (planMethodExample) so
   * both languages exercise identical shapes. Return [] to opt out.
   */
  generateTests?(spec: OpensdkSpecJson, ctx: EmitterContext): GeneratedFile[];

  /**
   * A single per-operation USAGE SNIPPET (optional) — a self-contained,
   * runnable-looking example that constructs the client and makes ONE call with
   * required-only example values (the artifact docs render, à la
   * Fern/Speakeasy/Stainless: `client.pets.list(...)`). `chain` is the resource
   * name path (root→owner) the method hangs off, so the emitter can rebuild the
   * client attribute chain in its own casing. Reuses the shared example planner
   * (planMethodExample) so every language shows the same call shape. Pure.
   */
  generateUsage?(method: Method, chain: string[], ctx: EmitterContext): string;

  /**
   * A single per-operation TYPE REFERENCE (optional) — the request params type +
   * response type as language-rendered field rows, plus the method signature.
   * The artifact an SDK-native reference renders (à la OpenAI's Go docs:
   * `AudioTranscriptionNewParams` with typed rows + a "Returns" type), replacing
   * the REST "query params" framing. `chain` is the resource-name path
   * (root→owner). Reuses the shared `planTypeReference`. Pure.
   */
  generateTypeReference?(method: Method, chain: string[], ctx: EmitterContext): RenderedTypeReference;
}

/** One language-rendered field row of an SDK type (shown in Atlas). */
export interface RenderedTypeField {
  /** Language field name (Go PascalCase, Python snake_case, ...). */
  name: string;
  /** Language type string (Go `param.Opt[string]`, TS `string | null`, ...). */
  langType: string;
  required: boolean;
  description?: string;
  deprecated?: boolean;
  /** When the field type is a named type: the ORIGINAL IR schema name, for a
   * cross-type link (`objects/<name>`). */
  refTypeName?: string;
}

/** One SDK type (request params / a response struct) as rendered field rows. */
export interface RenderedTypeGroup {
  /** Synthesized params-type NAME where the language has one (Go/Node/Java);
   * undefined for languages that flatten params (Python/Ruby/.NET). */
  typeName?: string;
  /** The method-argument name the params type is passed as (`body`/`query`/`params`)
   * — the root label, e.g. `query SessionListParams`. Undefined when the language
   * flattens params into the call (no single argument). */
  argName?: string;
  fields: RenderedTypeField[];
}

/** A per-operation TYPE reference, rendered in one language. */
export interface RenderedTypeReference {
  /** The method signature, e.g. `client.Audio.Transcriptions.New(ctx, body) (*Response, error)`. */
  signature: string;
  request: RenderedTypeGroup;
  response: {
    /** The response type's language name (the "Returns" heading). */
    typeName?: string;
    /** Struct field rows; absent for binary/scalar/open-union responses. */
    fields?: RenderedTypeField[];
    /** Fallback display for a non-struct response (e.g. `[]Pet`, `*http.Response`). */
    langType?: string;
    /** A human note for non-field responses ("binary download (audio/mpeg)"). */
    note?: string;
  };
}

/** Plugin bundle a consumer registers (mirrors oagen's config shape). */
export interface OpensdkConfig {
  emitters?: Emitter[];
}
